"""Test script to observe how claude -p sessions appear in the dashboard.

Run this in a separate terminal:
    python3 scripts/test_headless.py

It launches 'claude -p' via subprocess (mimicking meet-summarize),
pauses so you can inspect ~/.claude/sessions/*.json and the dashboard,
then cleans up.
"""

import json
import subprocess
import sys
import tempfile
import time
from pathlib import Path

SESSIONS_DIR = Path.home() / ".claude" / "sessions"


def dump_sessions(label: str):
    """Print all session files with their full content."""
    print(f"\n{'=' * 60}")
    print(f"  {label}")
    print(f"{'=' * 60}")
    for f in sorted(SESSIONS_DIR.glob("*.json")):
        try:
            data = json.loads(f.read_text())
            cwd = data.get("cwd", "?")
            if "tmp" in cwd.lower() or "test_headless" in cwd.lower():
                print(f"\n  {f.name}:")
                print(f"    {json.dumps(data, indent=4)}")
        except Exception:
            pass
    print()


def main():
    with tempfile.TemporaryDirectory(prefix="test_headless_") as tmpdir:
        print(f"Temp dir: {tmpdir}")
        print(f"Launching: claude -p 'sleep for 30 seconds then say hi'")
        print(f"Watch the dashboard and session files...\n")

        proc = subprocess.Popen(
            ["claude", "-p", "sleep for 30 seconds then say hi"],
            cwd=tmpdir,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
        )

        print(f"PID: {proc.pid}")
        print("Waiting 5s for session file to appear...")
        time.sleep(5)

        dump_sessions("WHILE RUNNING")

        print("Waiting for claude to finish (up to 60s)...")
        try:
            stdout, stderr = proc.communicate(timeout=60)
            print(f"Exit code: {proc.returncode}")
            print(f"Stdout: {stdout[:200]}")
        except subprocess.TimeoutExpired:
            proc.kill()
            print("Timed out, killed process")

        time.sleep(2)
        dump_sessions("AFTER EXIT")

        print("Check the dashboard now — is there a ghost for this temp dir?")
        print("Press Enter to clean up...")
        input()


if __name__ == "__main__":
    main()
